'use client';

import * as React from 'react';
import { NumberPicker } from '@/components/ui/number-picker';
import { SnapPicker } from '@/components/ui/snap-picker';
import { cn } from '@/lib/utils';

export type TimeFormat = '12h' | '24h';
export type Meridiem = 'AM' | 'PM';

export interface TimePickerValue {
  /** 0–23 in 24h form, regardless of display format. */
  hour: number;
  minute: number;
  second?: number;
}

export interface TimePickerProps {
  value: TimePickerValue;
  onChange: (value: TimePickerValue) => void;
  format?: TimeFormat;
  /** IANA timezone for display; defaults to the browser's local zone. */
  timezone?: string;
  showSeconds?: boolean;
  minuteStep?: number;
  secondStep?: number;
  itemHeight?: number;
  visibleCount?: number;
  label?: string;
  className?: string;
  disabled?: boolean;
}

const MERIDIEMS: Meridiem[] = ['AM', 'PM'];

const to12h = (hour24: number): { hour12: number; meridiem: Meridiem } => {
  const meridiem: Meridiem = hour24 < 12 ? 'AM' : 'PM';
  const hour12 = hour24 % 12 === 0 ? 12 : hour24 % 12;
  return { hour12, meridiem };
};

const to24h = (hour12: number, meridiem: Meridiem): number => {
  if (meridiem === 'AM') return hour12 === 12 ? 0 : hour12;
  return hour12 === 12 ? 12 : hour12 + 12;
};

/**
 * Compute the offset between a given IANA timezone and the local browser
 * zone in minutes. We use this to convert the user-supplied 24h hour into
 * the display hour for the target timezone.
 */
const getZoneOffsetMinutes = (timezone: string, at: Date = new Date()): number => {
  try {
    const dtf = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      hourCycle: 'h23',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
    const parts = dtf.formatToParts(at);
    const get = (type: string): number =>
      Number(parts.find((p) => p.type === type)?.value ?? '0');
    const asUTC = Date.UTC(
      get('year'),
      get('month') - 1,
      get('day'),
      get('hour'),
      get('minute'),
      get('second'),
    );
    return Math.round((asUTC - at.getTime()) / 60000);
  } catch {
    return 0;
  }
};

const shiftHour = (hour24: number, minuteOffset: number): number => {
  const totalMinutes = (hour24 * 60 + minuteOffset + 24 * 60) % (24 * 60);
  return Math.floor(totalMinutes / 60);
};

export const TimePicker = ({
  value,
  onChange,
  format = '24h',
  timezone,
  showSeconds = false,
  minuteStep = 1,
  secondStep = 1,
  itemHeight = 60,
  visibleCount = 5,
  label,
  className,
  disabled,
}: TimePickerProps): React.ReactElement => {
  const offsetMinutes = React.useMemo(
    () => (timezone ? getZoneOffsetMinutes(timezone) : 0),
    [timezone],
  );

  const displayHour24 = React.useMemo(
    () => shiftHour(value.hour, offsetMinutes),
    [value.hour, offsetMinutes],
  );

  const setHourFromDisplay = React.useCallback(
    (displayHour: number): void => {
      const canonical = shiftHour(displayHour, -offsetMinutes);
      onChange({ ...value, hour: canonical });
    },
    [offsetMinutes, onChange, value],
  );

  const columns: React.ReactNode[] = [];

  if (format === '24h') {
    columns.push(
      <NumberPicker
        key="hour"
        min={0}
        max={23}
        step={1}
        pad={2}
        value={displayHour24}
        onChange={setHourFromDisplay}
        itemHeight={itemHeight}
        visibleCount={visibleCount}
        loop
        label="Hour"
        disabled={disabled}
      />,
    );
  } else {
    const { hour12, meridiem } = to12h(displayHour24);
    columns.push(
      <NumberPicker
        key="hour12"
        min={1}
        max={12}
        step={1}
        pad={2}
        value={hour12}
        onChange={(h) => setHourFromDisplay(to24h(h, meridiem))}
        itemHeight={itemHeight}
        visibleCount={visibleCount}
        loop
        label="Hour"
        disabled={disabled}
      />,
    );
    columns.push(
      <SnapPicker<Meridiem>
        key="meridiem"
        items={MERIDIEMS}
        value={meridiem}
        onChange={(m) => setHourFromDisplay(to24h(hour12, m))}
        itemHeight={itemHeight}
        visibleCount={visibleCount}
        label="AM/PM"
        disabled={disabled}
      />,
    );
  }

  columns.splice(
    1,
    0,
    <NumberPicker
      key="minute"
      min={0}
      max={59}
      step={minuteStep}
      pad={2}
      value={value.minute}
      onChange={(minute) => onChange({ ...value, minute })}
      itemHeight={itemHeight}
      visibleCount={visibleCount}
      loop
      label="Minute"
      disabled={disabled}
    />,
  );

  if (showSeconds) {
    columns.splice(
      2,
      0,
      <NumberPicker
        key="second"
        min={0}
        max={59}
        step={secondStep}
        pad={2}
        value={value.second ?? 0}
        onChange={(second) => onChange({ ...value, second })}
        itemHeight={itemHeight}
        visibleCount={visibleCount}
        loop
        label="Second"
        disabled={disabled}
      />,
    );
  }

  return (
    <div
      role="group"
      aria-label={label ?? 'Time picker'}
      className={cn('flex items-stretch gap-2', className)}
    >
      {columns.map((col, i) => (
        <div key={i} className="flex-1">
          {col}
        </div>
      ))}
    </div>
  );
};
